handlebars/handlebars.js:    mod(require("../../lib/codemirror"), require("../../addon/mode/simple"), require("../../addon/mode/multiplex"));
htmlembedded/htmlembedded.js:        require("../../addon/mode/multiplex"));
modelica/modelica.js:    mod(require("../../lib/codemirror"));
nsis/nsis.js:    mod(require("../../lib/codemirror"), require("../../addon/mode/simple"));
rst/rst.js:    mod(require("../../lib/codemirror"), require("../python/python"), require("../stex/stex"), require("../../addon/mode/overlay"));
